def validate(args, output):
    n, m, group, beforeItems = args[0], args[1], args[2], args[3]
    if not isinstance(output, list):
        return False
    # decide feasibility independently by recomputing whether ANY order exists
    grp = list(group)
    nxt = m
    for i in range(n):
        if grp[i] == -1:
            grp[i] = nxt
            nxt += 1
    from collections import defaultdict, deque
    def toposort(nodes, edges):
        indeg = {x: 0 for x in nodes}
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            indeg[b] += 1
        q = deque([x for x in nodes if indeg[x] == 0])
        order = []
        while q:
            u = q.popleft()
            order.append(u)
            for v in adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    q.append(v)
        return order if len(order) == len(nodes) else None
    item_edges = []
    group_edges = set()
    for i in range(n):
        for j in beforeItems[i]:
            item_edges.append((j, i))
            if grp[j] != grp[i]:
                group_edges.add((grp[j], grp[i]))
    items_ok = toposort(list(range(n)), item_edges)
    groups_ok = toposort(list(range(nxt)), list(group_edges))
    feasible = items_ok is not None and groups_ok is not None
    # if infeasible, only an empty list is valid
    if not feasible:
        return output == []
    # feasible: empty list is NOT acceptable; output must be a real valid order
    if len(output) != n:
        return False
    if sorted(output) != list(range(n)):
        return False
    pos = {v: idx for idx, v in enumerate(output)}
    # 1. same group contiguous
    seen_groups = []
    last = None
    runs = {}
    for v in output:
        g = grp[v]
        if g != last:
            if g in runs:
                return False  # group appears in a non-contiguous block
            runs[g] = True
            last = g
    # 2. every beforeItems constraint respected
    for i in range(n):
        for j in beforeItems[i]:
            if pos[j] >= pos[i]:
                return False
    return True

