function validate(args, output) {
    const n = args[0], m = args[1], group = args[2], beforeItems = args[3];
    if (!Array.isArray(output)) return false;
    const grp = group.slice();
    let nxt = m;
    for (let i = 0; i < n; i++) if (grp[i] === -1) grp[i] = nxt++;
    function toposort(numNodes, edges) {
        const indeg = new Array(numNodes).fill(0);
        const adj = Array.from({length: numNodes}, () => []);
        for (const [a, b] of edges) { adj[a].push(b); indeg[b]++; }
        const q = [];
        for (let x = 0; x < numNodes; x++) if (indeg[x] === 0) q.push(x);
        let cnt = 0, head = 0;
        while (head < q.length) {
            const u = q[head++];
            cnt++;
            for (const v of adj[u]) { if (--indeg[v] === 0) q.push(v); }
        }
        return cnt === numNodes;
    }
    const itemEdges = [];
    const groupEdgeSet = new Set();
    for (let i = 0; i < n; i++) {
        for (const j of beforeItems[i]) {
            itemEdges.push([j, i]);
            if (grp[j] !== grp[i]) groupEdgeSet.add(grp[j] + ',' + grp[i]);
        }
    }
    const groupEdges = [...groupEdgeSet].map(s => s.split(',').map(Number));
    const feasible = toposort(n, itemEdges) && toposort(nxt, groupEdges);
    if (!feasible) return output.length === 0;
    if (output.length !== n) return false;
    const sortedOut = output.slice().sort((a, b) => a - b);
    for (let i = 0; i < n; i++) if (sortedOut[i] !== i) return false;
    const pos = new Array(n);
    for (let idx = 0; idx < output.length; idx++) pos[output[idx]] = idx;
    let last = null;
    const seenRuns = new Set();
    for (const v of output) {
        const g = grp[v];
        if (g !== last) {
            if (seenRuns.has(g)) return false;
            seenRuns.add(g);
            last = g;
        }
    }
    for (let i = 0; i < n; i++) {
        for (const j of beforeItems[i]) {
            if (pos[j] >= pos[i]) return false;
        }
    }
    return true;
}

