class Solution:
    def sortItems(self, n, m, group, beforeItems):
        from collections import defaultdict, deque
        gid = m
        grp = list(group)
        for i in range(n):
            if grp[i] == -1:
                grp[i] = gid
                gid += 1
        def topo(adj, indeg, nodes):
            q = deque(x for x in nodes if indeg[x] == 0)
            order = []
            while q:
                u = q.popleft()
                order.append(u)
                for v in adj[u]:
                    indeg[v] -= 1
                    if indeg[v] == 0:
                        q.append(v)
            return order if len(order) == len(nodes) else None
        item_adj = defaultdict(list)
        item_in = [0] * n
        group_adj = defaultdict(list)
        group_in = [0] * gid
        gseen = set()
        for i in range(n):
            for j in beforeItems[i]:
                item_adj[j].append(i)
                item_in[i] += 1
                if grp[j] != grp[i] and (grp[j], grp[i]) not in gseen:
                    gseen.add((grp[j], grp[i]))
                    group_adj[grp[j]].append(grp[i])
                    group_in[grp[i]] += 1
        item_order = topo(item_adj, item_in, list(range(n)))
        group_order = topo(group_adj, group_in, list(range(gid)))
        if item_order is None or group_order is None:
            return []
        buckets = defaultdict(list)
        for it in item_order:
            buckets[grp[it]].append(it)
        res = []
        for g in group_order:
            res.extend(buckets[g])
        return res

