var sortItems = function(n, m, group, beforeItems) {
    let gid = m;
    const grp = group.slice();
    for (let i = 0; i < n; i++) if (grp[i] === -1) grp[i] = gid++;
    function topo(adj, indeg, numNodes) {
        const q = [];
        for (let x = 0; x < numNodes; x++) if (indeg[x] === 0) q.push(x);
        const order = [];
        let head = 0;
        while (head < q.length) {
            const u = q[head++];
            order.push(u);
            for (const v of adj[u]) { if (--indeg[v] === 0) q.push(v); }
        }
        return order.length === numNodes ? order : null;
    }
    const itemAdj = Array.from({length: n}, () => []);
    const itemIn = new Array(n).fill(0);
    const groupAdj = Array.from({length: gid}, () => []);
    const groupIn = new Array(gid).fill(0);
    const gseen = new Set();
    for (let i = 0; i < n; i++) {
        for (const j of beforeItems[i]) {
            itemAdj[j].push(i);
            itemIn[i]++;
            if (grp[j] !== grp[i]) {
                const key = grp[j] + ',' + grp[i];
                if (!gseen.has(key)) {
                    gseen.add(key);
                    groupAdj[grp[j]].push(grp[i]);
                    groupIn[grp[i]]++;
                }
            }
        }
    }
    const itemOrder = topo(itemAdj, itemIn, n);
    const groupOrder = topo(groupAdj, groupIn, gid);
    if (itemOrder === null || groupOrder === null) return [];
    const buckets = new Map();
    for (const it of itemOrder) {
        if (!buckets.has(grp[it])) buckets.set(grp[it], []);
        buckets.get(grp[it]).push(it);
    }
    const res = [];
    for (const g of groupOrder) {
        if (buckets.has(g)) res.push(...buckets.get(g));
    }
    return res;
};
